(function(window){
    'use strict';

    function parseText(text) {
        var rows = [];
        var row = [];
        var field = '';
        var inQuotes = false;
        var i;
        var char;
        var next;

        function pushField() {
            row.push(field);
            field = '';
        }

        function pushRow() {
            pushField();
            rows.push(row);
            row = [];
        }

        for (i = 0; i < text.length; i++) {
            char = text.charAt(i);
            next = i + 1 < text.length ? text.charAt(i + 1) : '';

            if (inQuotes) {
                if (char === '"') {
                    if (next === '"') {
                        field += '"';
                        i++;
                    } else {
                        inQuotes = false;
                    }
                } else {
                    field += char;
                }
                continue;
            }

            if (char === '"') {
                inQuotes = true;
                continue;
            }

            if (char === ',') {
                pushField();
                continue;
            }

            if (char === '\r') {
                if (next === '\n') {
                    i++;
                }
                pushRow();
                continue;
            }

            if (char === '\n') {
                pushRow();
                continue;
            }

            field += char;
        }

        if (field !== '' || row.length > 0 || text.slice(-1) === ',') {
            pushRow();
        }

        return rows;
    }

    function isEmptyRow(row) {
        if (!row || !row.length) {
            return true;
        }

        return row.every(function(value) {
            return String(value || '').trim() === '';
        });
    }

    function toObjects(rows, options) {
        var fields = rows.length ? rows[0].map(function(value) {
            return String(value || '');
        }) : [];
        var data = [];
        var errors = [];
        var i;
        var row;
        var obj;
        var col;

        for (i = 1; i < rows.length; i++) {
            row = rows[i];

            if (options.skipEmptyLines && isEmptyRow(row)) {
                continue;
            }

            obj = {};

            for (col = 0; col < fields.length; col++) {
                obj[fields[col]] = col < row.length ? row[col] : '';
            }

            if (row.length > fields.length) {
                obj.__parsed_extra = row.slice(fields.length);
                errors.push({
                    type: 'FieldMismatch',
                    code: 'TooManyFields',
                    row: i,
                    message: 'Too many fields in row ' + (i + 1)
                });
            } else if (row.length < fields.length) {
                errors.push({
                    type: 'FieldMismatch',
                    code: 'TooFewFields',
                    row: i,
                    message: 'Too few fields in row ' + (i + 1)
                });
            }

            data.push(obj);
        }

        return {
            data: data,
            errors: errors,
            meta: {
                fields: fields
            }
        };
    }

    function quote(value) {
        var normalized = value == null ? '' : String(value);
        if (/[",\r\n]/.test(normalized)) {
            return '"' + normalized.replace(/"/g, '""') + '"';
        }
        return normalized;
    }

    function unparse(config) {
        var fields = Array.isArray(config.fields) ? config.fields : [];
        var data = Array.isArray(config.data) ? config.data : [];
        var lines = [];

        if (fields.length) {
            lines.push(fields.map(quote).join(','));
        }

        data.forEach(function(row) {
            var values = fields.map(function(field) {
                return Object.prototype.hasOwnProperty.call(row, field) ? row[field] : '';
            });
            lines.push(values.map(quote).join(','));
        });

        return lines.join('\r\n');
    }

    window.Papa = window.Papa || {};

    window.Papa.parse = function(file, options) {
        var settings = options || {};
        var reader = new FileReader();

        reader.onload = function(event) {
            try {
                var text = typeof event.target.result === 'string' ? event.target.result : '';
                var rows = parseText(text);
                var parsed;

                if (settings.header) {
                    parsed = toObjects(rows, settings);
                } else {
                    parsed = {
                        data: rows,
                        errors: [],
                        meta: {}
                    };
                }

                if (typeof settings.complete === 'function') {
                    settings.complete(parsed);
                }
            } catch (error) {
                if (typeof settings.error === 'function') {
                    settings.error(error);
                }
            }
        };

        reader.onerror = function() {
            if (typeof settings.error === 'function') {
                settings.error(reader.error || new Error('Unable to read file.'));
            }
        };

        reader.readAsText(file);
    };

    window.Papa.unparse = unparse;
})(window);
